  translate: 0 0;
}

/*   EXIT STATE   */
dialog {
  transition: opacity 1s, display 1s allow-discrete, overlay 1s allow-discrete;
  translate: 0 100vh;
}

/*   0. BEFORE-OPEN STATE   */
@starting-style {
  dialog[open] {
    translate: 0 100vh;
  }
}

